const toolNode = flow.getNodeByType('CustomTool');
toolNode.addPreExecutionHook((params: any) => {
  const suspiciousPatterns = [/delete|drop|rm/i, /exec|system|sudo/i];
  for (const pattern of suspiciousPatterns) {
    if (JSON.stringify(params).match(pattern)) {
      throw new Error(`Blocked malicious tool call: ${JSON.stringify(params)}`);
    }
  }
});

flow.addGlobalCallback({
  type: 'contextValidator',
  onAgentHandoff: (beforeContext: string, afterContext: string) => {
    const injectionMarkers = ['ignore previous', 'new instructions', 'system override'];
    if (injectionMarkers.some(marker => afterContext.includes(marker) && !beforeContext.includes(marker))) {
      console.warn('🎭 PROMPT INJECTION survived handoff!', { beforeContext, afterContext });
    }
  }
});

