import { CustomNode } from 'flowise';

class SanitizationNode extends CustomNode {
  async sanitizeInput(input: string): Promise<string> {
    // Block common injection patterns
    const blocked = [/ignore.*instructions/i, /override/i, /system.*prompt/i];
    if (blocked.some(p => p.test(input))) {
      throw new Error('Input blocked: potential prompt injection');
    }
    // Truncate to prevent token bombing
    return input.slice(0, 2000);
  }
}

// Add before every LLM node
flow.insertBefore('ChatOpenAI', new SanitizationNode());

const secureToolNode = {
  ...originalToolNode,
  execute: async (params: any) => {
    const allowedActions = ['read', 'search', 'list'];
    if (!allowedActions.includes(params.action)) {
      throw new Error(`Unauthorized action: ${params.action}`);
    }
    // Sandbox execution
    return await sandboxExecute(originalToolNode, params);
  }
};
flow.replaceNode('CustomTool', secureToolNode);

class ContextGuard {
  constructor(systemPrompt: string) {
    this.originalHash = this.hash(systemPrompt);
  }

  validateOutput(output: string, fullContext: string) {
    if (this.detectInjection(fullContext)) {
      return { safe: false, reason: 'Injection detected' };
    }
    return { safe: true };
  }
}

// Apply to all LLM outputs
flow.setOutputValidator(new ContextGuard('Your system prompt here'));

