import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise';

// Install: npm install flowise @vex_dev/sdk

const vex = new Vex({
  projectId: 'your-vex-project',
  apiKey: process.env.VEX_API_KEY
});

const flow = await ChatFlow.findChatflowByID('your-flow-id');

// Add Vex as primary callback handler
flow.callbacks = [
  {
    type: 'vex-guard',
    handler: async (event: any) => {
      const result = await vex.detect({
        framework: 'flowise',
        eventType: event.type,
        payload: event.input || event.context,
        flowId: flow.id,
        nodePath: event.nodePath
      });

      if (!result.safe) {
        // Auto-remediate
        await vex.applyFix(flow.id, result.recommendation);
        throw new Error(`Vex blocked: ${result.threat}`);
      }
    }
  }
];

await flow.save();
console.log('✅ Vex protection enabled for Flowise agent');
